import { IMessageComposer } from '@nitrots/nitro-renderer';

export class ArenaLeaveQueueComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor() {
        // No payload needed, server just needs the fact that we clicked "leave"
        this._data = [];
        console.log('[📤] ArenaLeaveQueueComposer sent');
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
